import * as Print from 'expo-print';
import { Participante } from './participantService';
import { Evento } from './eventService';

// Uma chave secreta simples para gerar o código de autenticação offline
const SECRET_SALT = 'SEDUC-CHECKIN-2026-v2';

/**
 * Gera um código de autenticação único baseado nos dados do participante
 */
const generateAuthCode = (participante: Participante, evento: Evento): string => {
  const raw = `${participante.id}-${evento.id}-${SECRET_SALT}`;
  // Um hash simples para gerar um código alfanumérico curto de 8 caracteres
  let hash = 0;
  for (let i = 0; i < raw.length; i++) {
    const char = raw.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }
  const code = Math.abs(hash).toString(36).toUpperCase();
  return `${code.substring(0, 4)}-${code.substring(4, 8)}`;
};

/**
 * Formata CPF para 000.000.000-00
 */
export const formatCPF = (cpf?: string): string => {
  if (!cpf) return '---';
  const clean = cpf.replace(/\D/g, '');
  if (clean.length !== 11) return cpf; // Retorna original se não tiver 11 dígitos
  return `${clean.substring(0, 3)}.${clean.substring(3, 6)}.${clean.substring(6, 9)}-${clean.substring(9, 11)}`;
};

/**
 * Gera o texto formatado que será inserido no QR Code para leitura por qualquer câmera
 */
export const getDeclarationQRText = (participante: Participante, evento: Evento): string => {
  const authCode = generateAuthCode(participante, evento);
  const time = participante.checkInTime || 'N/A';

  return `DECLARAÇÃO DE PRESENÇA\n` +
    `Nome: ${participante.nome}\n` +
    `CPF: ${formatCPF(participante.cpf)}\n` +
    `Evento: ${evento.nome}\n` +
    `Data: ${evento.data}\n` +
    `Check-in: ${time}\n` +
    `Validação: ${authCode}`;
};

/**
 * Gera o HTML para o PDF da Declaração
 */
export const getDeclarationHtml = (participante: Participante, evento: Evento, qrCodeDataUrl: string): string => {
  const authCode = generateAuthCode(participante, evento);
  const dateStr = new Date().toLocaleDateString('pt-BR');

  // URL do logo (O usuário deve colocar o arquivo em assets/images/logo_educacao.png)
  // Para o PDF, o ideal é usar Base64 ou um caminho web. Usaremos um placeholder se o real não for resolvido.
  const logoUrl = 'data:image/png;base64,'; // Exemplo de fallback ou caminho resolvido

  return `
    <!DOCTYPE html>
    <html lang="pt-BR">
    <head>
      <meta charset="UTF-8">
      <style>
        body { font-family: 'Helvetica', 'Arial', sans-serif; color: #333; margin: 0; padding: 0; }
        .certificate-container {
          border: 10px solid #ececec;
          padding: 40px;
          margin: 10px;
          text-align: center;
          background-color: #fff;
          min-height: 850px;
          display: flex;
          flex-direction: column;
          justify-content: space-between;
        }
        .header-logo { width: 300px; margin-bottom: 20px; }
        .title { font-size: 28px; color: #000; font-weight: bold; margin-bottom: 5px; }
        .subtitle { font-size: 16px; color: #666; margin-bottom: 60px; font-weight: normal; }
        .content { font-size: 19px; line-height: 1.8; margin-bottom: 60px; text-align: justify; padding: 0 30px; }
        .highlight { font-weight: bold; color: #000; }
        
        .footer { display: flex; justify-content: space-between; align-items: flex-end; padding: 0 30px; }
        .verification-box { text-align: left; background: #f9f9f9; padding: 15px; border-radius: 8px; border: 1px solid #eee; }
        .qr-code { width: 120px; height: 120px; margin-bottom: 10px; }
        .auth-code { font-family: monospace; font-size: 12px; color: #777; }
        
        .signature-area { text-align: right; }
        .signature-line { border-top: 1px solid #000; width: 250px; margin-top: 50px; margin-left: auto; }
      </style>
    </head>
    <body>
      <div class="certificate-container">
        <div class="main-content">
          <center>
            <img src="${logoUrl}" class="header-logo" alt="Logo Educação Inclusiva" />
          </center>

          <div class="title">DECLARAÇÃO DE PRESENÇA</div>
          <div class="subtitle">Comprovante Oficial de Participação</div>

          <div class="content">
            Declaramos para os devidos fins que o(a) sevidor(a) <span class="highlight">${participante.nome.toUpperCase()}</span>, 
            inscrito sob o CPF: <span class="highlight">${formatCPF(participante.cpf)}</span>, no cargo de 
            <span class="highlight">${participante.funcao}</span>, compareceu e participou do evento 
            <span class="highlight">${evento.nome}</span> realizado em <span class="highlight">${evento.data}</span>.
          </div>
        </div>

        <div class="footer">
          <div class="verification-box">
             <img src="${qrCodeDataUrl}" class="qr-code" />
             <div style="font-size: 10px; color: #666; margin-bottom: 5px;">Aponte a câmera para validar</div>
             <div class="auth-code">Autenticação: ${authCode}</div>
          </div>
          
          <div class="signature-area">
            <p>Emitido em ${dateStr}</p>
            <div class="signature-line"></div>
            <p style="font-size: 14px; margin-top: 5px;">Coordenação de Eventos</p>
          </div>
        </div>
      </div>
    </body>
    </html>
  `;
};

/**
 * Gera o arquivo PDF
 */
export const generateDeclarationPdf = async (participante: Participante, evento: Evento, qrCodeDataUrl: string) => {
  const html = getDeclarationHtml(participante, evento, qrCodeDataUrl);
  const { uri } = await Print.printToFileAsync({ html });
  return uri;
};
